    ```java
public int findSubstringInWraproundString(String p) {
    int[] cnt = new int[26];
    int length = 0;

    for (int i = 0; i < p.length(); i++) {
        if (i > 0 && (p.charAt(i) == p.charAt(i - 1) + 1 || p.charAt(i - 1) - p.charAt(i) == 25)) {
            length++;
        } else {
            length = 1;
        }
        cnt[p.charAt(i) - 'a'] = Math.max(cnt[p.charAt(i) - 'a'], length);
    }

    int sum = 0;
    for (int v : cnt) {
        sum += v;
    }
    return sum;
}
```


